  ('dietitian-moex-08724', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '若酵素催化一反應遵守Michaelis-Menten方程式，則以反應速率對基質濃度作圖之圖形為：', '["sigmoid curve", "hyperbolic curve", "linear line", "concave curve"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08725', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有一酵素抑制物可改變酵素之 Km，但不影響最大反應速率（Vmax），則此抑制物對酵素之抑制作用屬 何種抑制作用？', '["不可逆抑制作用（irreversible inhibition）", "競爭性抑制作用（competitive inhibition）", "非競爭性抑制作用（noncompetitive inhibition）", "未競爭性抑制作用（uncompetitive inhibition）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
