  ('dietitian-moex-08727', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關telomeres的敘述，下列何者錯誤？', '["位於真核細胞線性染色體的末端結構", "含有多個短序列的重覆", "隨著細胞的複製，其序列會逐漸增長", "藉由telomerase將telomere加至染色體"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08728', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '在ATP中，α-phosphate與核糖（ribose）的鍵結稱為：', '["ester linkage", "anhydride linkage", "covalent linkage", "disulfide linkage"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08729', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列coenzymes中何者不含有adenosine？', '["coenzyme A", "coenzyme Q", "nicotinamide adenine dinucleotide", "flavin adenine dinucleotide"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08730', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '尿素循環的代謝過程在肝臟細胞之細胞質中進行的反應是：', '["胺甲醯磷酸（carbamoyl-phosphate）之形成", "精胺酸酶（arginase）催化尿素自精胺酸（arginine）分子脫離", "尿素循環中與檸檬酸循環重疊的部分", "胺甲醯磷酸（carbamoyl-phosphate）與鳥胺酸（ornithine）結合產生瓜胺酸（citrulline）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08731', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關甘胺酸之代謝功能的敘述，何者正確？', '["參與組胺酸生合成時支鏈環狀構造的合成", "由甲硫胺酸得到硫而合成半胱胺酸", "參與嘌呤之生合成時，整個分子的碳與氮皆併入嘌呤之環狀結構中", "參與嘌呤之生合成時，甘胺酸提供嘌呤環外之胺基"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08732', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '構成蛋白質結構之氫鍵（hydrogen bond），下列敘述何者錯誤？', '["是由－NH或OH的H原子與－C=O中的O原子作用而成", "存於二條胜鍵之間或胜鍵本身的螺旋結構中", "是一種非共價鍵", "是一種構成蛋白質之初級結構的主要化學鍵之一"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08733', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '在蛋白質的α－螺旋（α-helix）結構中，有關氫鍵（hydrogen bond）的敘述，何者正確？', '["主要出現在最靠近氮端（N-terminus）的四個胺基酸之間", "主要出現在最靠近碳端（C-terminus）的四個胺基酸之間", "方向與α－螺旋的中心軸大致平行", "方向與α－螺旋的中心軸呈垂直關係"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
